INSERT INTO news (id, title, date, category, excerpt, image_key, external_link, sort_order) VALUES
(1, 'Новогоднее поздравление Руководителя Росприроднадзора Светланы Радионовой', '', 'Новости', '', NULL, 'https://t.me/Rosprirodnadzor_official/2680', 1),
(2, 'Михаил Мишустин провел встречу с главой Росприроднадзора Светланой Радионовой', '', 'Новости', '', NULL, 'https://t.me/omoreco/280', 2),
(3, 'Заместитель руководителя Росприроднадзора Владимир Чернышев об установлении квот выбросов для предприятий', '', 'Новости', '«Установление квот выбросов для предприятий – это часть масштабной работы, один из важных этапов по квотированию выбросов. Конечная цель – снизить уровень загрязнения воздуха. Предприятия должны достигать установленные лимиты по выбросам загрязняющих веществ, используя новые технологии, модернизацию оборудования или сокращая источники выбросов».', 'images/news3.jpg', NULL, 3),
(4, 'Оплата труда внештатных экспертов государственной экологической экспертизы с 2026 года увеличится почти в два раза', '', 'Законодательство', 'Минюст зарегистрировал приказ Минприроды, который корректирует действующие нормы 2013 и 2014 годов. Обновления призваны привести порядок оплаты и расчёта затрат по ГЭЭ в соответствие с современными требованиями и сделать систему финансирования более прозрачной и предсказуемой. Значительнее всего повышается вознаграждение руководителей экспертных комиссий: для федерального уровня сумма возрастает с 23 тысяч до 40 871 рубля (почти в 1,8 раза), для регионального — с 16 тысяч до 28 433 рублей.', NULL, 'https://t.me/omoreco/277', 4),
(5, 'Росприроднадзор совместно с ФГБУ "ФЦАО" провели обучающий семинар для природопользователей', '', 'Семинары', 'Семинар посвящен актуальным вопросам экологического контроля. Основные темы касались проведения инвентаризации выбросов и сбросов загрязняющих веществ, получения комплексных экологических разрешений, а также оснащения предприятий системами автоматического контроля и применения новых технологий, таких как беспилотники, VR-очки и приложение "Мобильный инспектор". Руководитель Службы Светлана Радионова приняла участие в семинаре.', 'images/news5.jpg', 'https://t.me/omoreco/275', 5),
(6, 'Генеральный директор ОМОР «Союз Экологов России» принял участие в «Школе региональных министров» Росприроднадзора', '6-8 ноября 2025', 'Новости', 'С 6 по 8 ноября 2025 г. в Мастерской управления «Сенеж» прошла «Школа региональных министров» Росприроднадзора, где собрались региональные министры экологии со всей страны.', 'images/news6.jpg', 'https://t.me/omoreco/268', 6),
(7, 'Президент Владимир Путин поддержал предложение о придании русскому языку статуса официального в рамках Конвенции СИТЕС', '', 'Новости', 'Россия намерена не только закрепить право на использование родного языка, но и активно продвигать свою позицию в других международных договорах — по биоразнообразию, обращению с отходами. Правительство РФ издало распоряжение о выделении средств на обеспечение синхронного перевода на русский язык на ближайшей Конференции сторон СИТЕС в Самарканде с 24 ноября по 5 декабря.', 'images/news7.jpg', NULL, 7),
(8, 'Правительство утвердило периодичность обязательных профилактических визитов для объектов контроля', '', 'Законодательство', 'Постановлением Правительства РФ №1511 установлена периодичность таких визитов в зависимости от категории риска контролируемого объекта:

• для объектов значительного риска - не более одного визита в 3 года;
• для объектов среднего риска - не более одного визита в 5 лет;
• для объектов умеренного риска – не более одного визита в 6 лет.

Профилактический визит – это одно из мероприятий, предусмотренных законом о государственном и муниципальном контроле в Российской Федерации.

Обязательный профилактический визит проводится исключительно по инициативе надзорного ведомства. Также могут проводиться обязательные профвизиты по поручению Президента или Правительства РФ.

Длительность визита не может превышать 10 рабочих дней. Однако она может быть продлена на время проведения необходимых экспертиз и испытаний.

Контролируемое лицо не может отказаться от такого профвизита. If провести его невозможно или лицо уклоняется от проведения обязательного профилактического визита, надзорный орган может в течение трех месяцев после составления акта о невозможности его проведения принять решение о повторном визите.

Обязательные профилактические визиты проводятся для стимулирования контролируемых лиц по соблюдению обязательных требований, установленных законодательством. Это помогает обеспечивать безопасность, предотвращать аварии, экологические ущербы и другие негативные последствия.', 'images/news8.jpg', 'https://t.me/omoreco/255', 8);

