INSERT INTO events (id, year, date, format, title, description, show_buy_button, is_past, sort_order) VALUES
(1, 2024, '5-7 марта 2024 г.', 'ОЧНО', 'Включение в Реестр утилизаторов: право или обязанность? Порядок исполнения РОП импортерами и производителями', 'В связи с началом реформы системы РОП, а также вступившими в силу нормативными правовыми актами новой системы регулирования с 05 по 07 марта 2024 года при непосредственном участии Федеральной службы по надзору в сфере природопользования проведено обучение по программе повышения квалификации «Включение в Реестр утилизаторов: право или обязанность? Порядок исполнения РОП импортерами и производителями».

Пленарное заседание прошло с участием Руководителя Федеральной службы по надзору в сфере природопользования Светланы Радионовой.

В семинаре приняли участие руководители и специалисты Росприроднадзора, непосредственно участвующие в выработке позиции контролирующего органа власти по данному вопросу, ведущие эксперты-практики.

Организаторами семинара выступили ОМОР «Союз Экологов России», ФГБУ «ФЦАО» и РУДН.', 0, 1, 1),
(2, 2024, '7 июня 2024 г.', 'ВКС', 'Требования, предъявляемые к испытательным лабораториям при осуществлении ПЭК. Актуальные вопросы при отборах проб и методическом обеспечении испытательных лабораторий', NULL, 1, 1, 2),
(3, 2024, '9 октября 2024 г.', 'ВКС', 'Расширенная ответственность производителей в 2024 году. Реестр утилизаторов', NULL, 1, 1, 3),
(4, 2024, '6 ноября 2024 г.', 'ВКС', 'Обращение с промышленными отходами', NULL, 1, 1, 4),
(5, 2024, '10 декабря 2024 г.', 'ВКС', 'Предоставление отчётов в Федеральную службу по надзору в сфере природопользования', NULL, 1, 1, 5);

